import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithTrim() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertFalse(original.getTrim());

        CSVFormat trimmed = original.withTrim(true);
        assertTrue(trimmed.getTrim());

        // Also test withTrim(boolean) with false to contrast
        CSVFormat notTrimmed = original.withTrim(false);
        assertFalse(notTrimmed.getTrim());

        // Ensure original is unchanged (immutability)
        assertFalse(original.getTrim());

        // Test chaining withTrim(true) explicitly
        CSVFormat explicitTrimmed = original.withTrim(true);
        assertTrue(explicitTrimmed.getTrim());

        // Test that withTrim() returns a new instance (not same as original)
        CSVFormat trimmedNoArg = original.withTrim();
        assertTrue(trimmedNoArg.getTrim());
        assertNotSame(original, trimmedNoArg);
    }
}
